#include <Arduino.h>
#include <math.h>
#include <TM1637.h>

// ===== CONFIG =====
#define ADC_PIN             36
#define FFT_SIZE            16
#define SAMPLE_RATE         4000
#define SMOOTH_WINDOW       4
#define CLK                 42
#define DIO                 41
#define LED_PIN             48
#define DETECTION_THRESHOLD 0.7f

TM1637 tm(CLK, DIO);

// ===== GLOBALS =====
float samples[FFT_SIZE];
float real_buf[FFT_SIZE];
float imag_buf[FFT_SIZE];
float confidence = 0.0f;

// ===== MOVING AVERAGE =====
float smoothSample(float newSample) {
    static float buffer[SMOOTH_WINDOW] = {0};
    static int idx = 0;
    static float sum = 0;
    sum -= buffer[idx];
    buffer[idx] = newSample;
    sum += newSample;
    idx = (idx + 1) % SMOOTH_WINDOW;
    return sum / SMOOTH_WINDOW;
}

// ===== 16-POINT DFT =====
void computeFFT() {
    for (int k = 0; k < FFT_SIZE; k++) {
        real_buf[k] = 0; imag_buf[k] = 0;
        for (int n = 0; n < FFT_SIZE; n++) {
            float angle = 2 * PI * k * n / FFT_SIZE;
            real_buf[k] += samples[n] * cos(angle);
            imag_buf[k] -= samples[n] * sin(angle);
        }
    }
}

void getMagnitudes(float *mag) {
    for (int i = 0; i < FFT_SIZE; i++)
        mag[i] = sqrtf(real_buf[i]*real_buf[i] + imag_buf[i]*imag_buf[i]);
}

