// ===== DRONENET INFERENCE =====
float runDroneNet(float *mag) {
    float wb[16];
    for (int i = 0; i < 16; i++) wb[i] = logf(1.0f + mag[i]) * 100.0f * FEAT_W[i];

    float x[33];
    for (int i = 0; i < 16; i++) x[i] = wb[i];
    for (int i = 0; i < 15; i++) x[16 + i] = wb[i + 1] - wb[i];
    float mean16 = 0, sum4 = 0;
    for (int i = 0; i < 16; i++) mean16 += wb[i];
    mean16 /= 16.0f;
    for (int i = 4; i < 16; i++) sum4 += wb[i];
    float var = 0;
    for (int i = 0; i < 16; i++) var += (wb[i] - mean16) * (wb[i] - mean16);
    x[31] = sum4 / 12.0f;
    x[32] = sqrtf(var / 16.0f);

    for (int i = 0; i < 33; i++) x[i] = (x[i] - IN_MEAN[i]) / IN_STD[i];

    float h0[64];
    for (int i = 0; i < 64; i++) {
        float v = b0[i];
        for (int j = 0; j < 33; j++) v += W0[i*33+j] * x[j];
        v = (v - bn1_rm[i]) / sqrtf(bn1_rv[i] + 1e-5f) * bn1_g[i] + bn1_b[i];
        h0[i] = v > 0 ? v : 0;
    }
    float h1[32];
    for (int i = 0; i < 32; i++) {
        float v = b4[i];
        for (int j = 0; j < 64; j++) v += W4[i*64+j] * h0[j];
        v = (v - bn5_rm[i]) / sqrtf(bn5_rv[i] + 1e-5f) * bn5_g[i] + bn5_b[i];
        h1[i] = v > 0 ? v : 0;
    }
    float h2[16];
    for (int i = 0; i < 16; i++) {
        float v = b8[i];
        for (int j = 0; j < 32; j++) v += W8[i*32+j] * h1[j];
        v = (v - bn9_rm[i]) / sqrtf(bn9_rv[i] + 1e-5f) * bn9_g[i] + bn9_b[i];
        h2[i] = v > 0 ? v : 0;
    }
    float logit = b12[0];
    for (int j = 0; j < 16; j++) logit += W12[j] * h2[j];
    return 1.0f / (1.0f + expf(-logit));
}

// ===== SETUP =====
void setup() {
    Serial.begin(115200);
    analogReadResolution(12);
    tm.begin();
}

// ===== LOOP =====
void loop() {
    for (int i = 0; i < FFT_SIZE; i++) {
        int raw = analogRead(ADC_PIN);
        samples[i] = smoothSample((float)(raw - 2048));
        delayMicroseconds(1000000 / SAMPLE_RATE);
    }

    computeFFT();
    float magnitudes[FFT_SIZE];
    getMagnitudes(magnitudes);

    confidence = runDroneNet(magnitudes);
    int pct = (int)(confidence * 100.0f + 0.5f);
    if (pct > 100) pct = 100;
    if (pct < 0)   pct = 0;

    tm.clearScreen();
    uint8_t offset = (pct < 10) ? 3 : (pct < 100) ? 2 : 1;
    tm.display(pct, false, false, offset);

    if (confidence >= DETECTION_THRESHOLD)
        neopixelWrite(LED_PIN, 255, 0, 0);
    else
        neopixelWrite(LED_PIN, 0, 100, 0);

    for (int i = 0; i < FFT_SIZE; i++) {
        Serial.print(magnitudes[i]);
        if (i < FFT_SIZE - 1) Serial.print(",");
    }
    Serial.print(" | confidence:");
    Serial.println(confidence);
}
